#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int result = -1;
        for (int i = 0; i < N; i++) {
            int temp = A[i];
            int diff = -1;
            for (int j = 0; j < N - 1; j++) {
                if (j != i) {
                    if (diff == -1) {
                        diff = A[j + 1] - A[j];
                    } else if (A[j + 1] - A[j] != diff) {
                        break;
                    }
                }
            }
            if (diff != -1) {
                if (result == -1 || temp < result) {
                    result = temp;
                }
            }
        }
        printf("%d\n", result);
    }
    return 0;
}

