        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int result = -1;
            for (int i = 0; i < N; i++) {
                int temp = A[i];
                int diff = -1;
                for (int j = 0; j < N - 1; j++) {
                    if (j != i) {
                        if (diff == -1) {
                            diff = A[j + 1] - A[j];
                        } else if (A[j + 1] - A[j] != diff) {
                            break;
                        }
